DROP DATABASE IF EXISTS amazon_transportation;
CREATE DATABASE amazon_transportation;
USE amazon_transportation;

CREATE TABLE routes (
    route_id VARCHAR(10) PRIMARY KEY,
    origin VARCHAR(50),
    destination VARCHAR(50),
    distance_miles INT,
    expected_transit_days INT
);
carrier_pickups
CREATE TABLE carriers (
    carrier_id VARCHAR(10) PRIMARY KEY,
    carrier_name VARCHAR(50),
    region VARCHAR(20)
);

CREATE TABLE shipments (
    shipment_id VARCHAR(10) PRIMARY KEY,
    route_id VARCHAR(10),
    carrier_id VARCHAR(10),
    shipment_date DATE,
    forecasted_volume INT,
    actual_volume INT,
    departed_on_time TINYINT,
    FOREIGN KEY (route_id) REFERENCES routes(route_id),
    FOREIGN KEY (carrier_id) REFERENCES carriers(carrier_id)
);

CREATE TABLE carrier_pickups (
    pickup_id VARCHAR(10) PRIMARY KEY,
    shipment_id VARCHAR(10),
    carrier_id VARCHAR(10),
    scheduled_pickup DATETIME,
    actual_pickup DATETIME,
    missed TINYINT,
    FOREIGN KEY (shipment_id) REFERENCES shipments(shipment_id)
);

